// =====================================================================
// PDF ENGINE CORE — banthacha-v2 Stage 9
// ครุฑ (base64) + createDocBase() สร้าง jsPDF doc พร้อมฟอนต์ไทย + ครุฑ + header
// 🔴 HIGH RISK STAGE — ถ้า font/ครุฑ ผิดตำแหน่งหรือ font ไม่ embed ถูก
// เอกสารทั้ง 16 ชุดใน Stage 17 จะพังหมด ต้องตรวจ test PDF ก่อนไปต่อเสมอ
// =====================================================================
const GARUDA_B64 = '';

function registerThaiFont(doc){
  doc.addFileToVFS('THSarabun.ttf', THSARABUN_REGULAR_B64);
  doc.addFont('THSarabun.ttf', 'THSarabun', 'normal');
  doc.addFileToVFS('THSarabun-Bold.ttf', THSARABUN_BOLD_B64);
  doc.addFont('THSarabun-Bold.ttf', 'THSarabun', 'bold');
}

// ═══════════════════════════════════════════════════════════════════
// ประวัติปัญหา thaiText() — เก็บไว้เพื่อไม่ให้แก้วนกลับไปที่วิธีเดิมที่พิสูจน์แล้วว่าผิด
// ═══════════════════════════════════════════════════════════════════
// รอบที่ 1-4 (2026-07-02 ถึง 2026-07-04): พยายามแก้ปัญหาสระ/วรรณยุกต์ "ลอย"/"ทับกัน" ด้วยการ
// แยกวาดวรรณยุกต์ (่ ้ ๊ ๋ ์) เองแล้วคำนวณตำแหน่ง x/y ด้วยมือ ทุกรอบ Pam ตรวจแล้วพบว่ายัง
// ผิดอยู่บางคำเสมอ — รอบที่ 5 เปลี่ยนไปใช้ canvas-to-image (render ผ่าน browser แล้วฝังเป็นรูป)
// ซึ่งถูกต้องแน่นอนแต่ทำให้ข้อความ copy/select ไม่ได้ — Pam ขอกลับไปแบบข้อความจริง (แบบเก่า)
//
// จุดพลิก (2026-07-04): ไล่โค้ดด้วยมือพบว่า "การแยกวาดเอง" ทุกเวอร์ชันที่ผ่านมาคือตัวปัญหา
// เอง ไม่ใช่ทางแก้ — ตรวจสอบฟอนต์ THSarabun.ttf ด้วย fontTools พบว่าวรรณยุกต์/สระบนทุกตัว
// ถูกออกแบบเป็น combining mark ที่ถูกต้องอยู่แล้ว: advance width = 0 และ left-side-bearing
// เป็นค่าลบ (ดึงตัวเองไปซ้อนบนตัวอักษรก่อนหน้าโดยอัตโนมัติ) — และตรวจ doc.getTextWidth()
// ของ jsPDF เองก็อ่านค่า advance=0 นี้ถูกต้อง (getTextWidth('น้อง') == getTextWidth('นอง'))
//
// ยืนยันด้วย HarfBuzz จริง (uharfbuzz — เอนจิน shaping ตัวเดียวกับที่ Chrome/Firefox ใช้):
// shape คำ 642 คำ (พยัญชนะ 5 ตัว × สระ 6 + วรรณยุกต์ 5 + สระอำ, ฟอนต์ปกติ+ตัวหนา, บวกคำจริง
// ที่เคยมีปัญหาทั้งหมด) ทุก glyph ได้ x_offset=0, y_offset=0 — แปลว่าฟอนต์นี้ไม่ได้ใช้ GPOS
// mark-attachment แบบซับซ้อน พึ่งแค่ hmtx (advance=0 + lsb ลบ) ล้วนๆ ซึ่ง jsPDF รองรับถูกต้อง
// อยู่แล้วโดยธรรมชาติเมื่อวาด string เต็มๆ ตรงๆ (ไม่ต้องแยกอักษรเอง)
//
// สรุป: การแยกวาดวรรณยุกต์เองทุกเวอร์ชัน (รอบ 1-4) คือสิ่งที่ทำให้ตำแหน่งผิด เพราะเขียนสูตร
// เดาเอง (x = getTextWidth(base), ค่า offset ต่างๆ) ทับพฤติกรรมที่ถูกต้องอยู่แล้วของฟอนต์ —
// ทางแก้ที่ถูกต้องคือ "ไม่ต้องทำอะไรเลย" ปล่อยให้ doc.text() วาด string ทั้งเส้นตรงๆ
//
// รอบที่ 7 (2026-07-04) — Pam ทดสอบเปรียบเทียบกับ Word (พิมพ์ "ก่" ด้วย TH SarabunPSK จริง)
// ยืนยันว่าวรรณยุกต์ "ลอยห่าง" ตอนติดพยัญชนะเปล่าๆ (ไม่มีสระบน) เป็นนิสัยของฟอนต์เองจริง
// (Word ก็แสดงผลแบบเดียวกัน) — วัด glyph bounding box จริงด้วย fontTools พบว่า:
//   พยัญชนะ (ก น ม ว ส บ)  ขอบบนอยู่ที่ 40-44% ของความสูงตัวอักษร (both regular & bold)
//   สระบน (ิ ี)            ขอบล่างอยู่ที่ 45%       → ห่างจากพยัญชนะแค่ ~1-5%
//   วรรณยุกต์ (่ ้ ๊ ๋)     ขอบล่างอยู่ที่ 66.7-68%  → ห่างจากพยัญชนะ ~23-28% (ลอยเพราะฟอนต์
//                                                      เผื่อพื้นที่ให้สระบนเสมอ ไม่ว่าจะมีจริงหรือไม่)
// รอบที่ 8-9 (2026-07-04) — Pam เจอ 2 เคสเพิ่มหลังแก้รอบ 7:
//  (ก) "ปั่น" — ป/ฝ/ฟ หัวสูงผิดปกติ (55.9%) ทำให้ "สระบน" (ิ ี ึ ื ั ขอบล่าง 45-46%) ชนหัว
//      ป/ฝ/ฟ เอง (ไม่เกี่ยวกับวรรณยุกต์เลย) — ต้องเลื่อน "สระบน" ขึ้นเมื่อติด ป/ฝ/ฟ ด้วย
//      และวรรณยุกต์ที่ตามหลังสระบนนั้นต้องเลื่อนขึ้นตามไปด้วยเท่ากัน (ไม่งั้นวรรณยุกต์จะ
//      ไปชนสระที่เพิ่งเลื่อนขึ้นแทน)
//  (ข) "ก้ำกึ่ง" — ส่วน "ก้ำ" คือวรรณยุกต์ติดพยัญชนะเปล่าแล้วตามด้วย ำ (ไม่ใช่สระบน) — โค้ด
//      รอบ 7 เห็นว่าไม่มีสระบนนำหน้าเลยเลื่อนลง 14% ทั้งที่ ำ เอง (ขอบบน 61.5%) กินพื้นที่
//      แทนสระอยู่แล้ว เลื่อนลงไปเลยไปชน ำ พอดี — ต้องเช็คด้วยว่าตามด้วย ำ ไหม ถ้าใช่ไม่ต้อง
//      เลื่อนเลย (ของเดิมห่างจาก ำ พอดีอยู่แล้ว ~6%)
//
// วัด glyph bounding box จริงด้วย fontTools ครบทุกตัวที่เกี่ยวข้อง (ทั้ง regular และ bold
// ตรงกันในช่วง ±2%) ได้ตัวเลขตั้งต้นสำหรับคำนวณค่าเลื่อนทุกค่าด้านล่าง (ไม่มีค่าไหนกะเอา):
//   พยัญชนะทั่วไป ขอบบน 40-44% | ป/ฝ/ฟ ขอบบน 55.9% | สระบน ขอบล่าง 45-46.4% ขอบบน 60-65%
//   ำ ขอบบน 61.5-63.4% | วรรณยุกต์ ขอบล่าง 66.7-68% ขอบบน 79-84.4%
const SARA_TONE_ONLY  = ['่','้','๊','๋'];              // วรรณยุกต์ (ไม่รวม ์ การันต์ ซึ่งไม่ได้ลอยแบบนี้)
const SARA_ABOVE_VOWEL = ['ิ','ี','ึ','ื','ั'];          // สระบน
const SARA_AM = 'ำ';
const TALL_CONSONANTS = ['ป', 'ฝ', 'ฟ'];                // วัดจริงแล้วสูงกว่าพยัญชนะอื่นชัดเจน (55.9% vs 40-44%)

const TONE_SHIFT_DOWN_NORMAL = 0.14;   // วรรณยุกต์ติดพยัญชนะเปล่าปกติ (ไม่มีสระ ไม่มี ำ ตาม) — เลื่อนลง
const TONE_SHIFT_DOWN_TALL   = 0.08;   // วรรณยุกต์ติด ป/ฝ/ฟ เปล่าๆ (ไม่มีสระ ไม่มี ำ ตาม) — เลื่อนลงน้อยกว่า
const MARK_SHIFT_UP_TALL     = 0.13;   // สระบน (และวรรณยุกต์ที่ตามหลังสระนั้น) ที่ติด ป/ฝ/ฟ — เลื่อนขึ้นเท่ากันทั้งคู่

// วาดข้อความไทย — ปกติเป็นแค่ wrapper บางๆ รอบ doc.text() (จัดการ align เท่านั้น) ไม่แยก
// อักษรเอง ยกเว้น 3 กรณีที่วัดแล้วว่าฟอนต์วางตำแหน่งไม่พอดี (ดูคอมเมนต์ด้านบน):
//   1. วรรณยุกต์ติดพยัญชนะเปล่าๆ (ไม่มีสระ ไม่มี ำ ตาม) → เลื่อนลง (14% ปกติ / 8% ถ้าติด ป ฝ ฟ)
//   2. สระบนติด ป/ฝ/ฟ → เลื่อนขึ้น 13%
//   3. วรรณยุกต์ที่ตามหลังสระบนซึ่งติด ป/ฝ/ฟ (เคสก่อนหน้า) → เลื่อนขึ้น 13% เท่ากัน (กันไม่ให้
//      วรรณยุกต์ไปชนสระที่เพิ่งเลื่อนขึ้น)
function thaiText(doc, str, x, y, opts){
  opts = opts || {};
  let startX = x;
  if(opts.align === 'center'){
    startX = x - doc.getTextWidth(str) / 2;
  } else if(opts.align === 'right'){
    startX = x - doc.getTextWidth(str);
  }

  // หาพยัญชนะฐานของตำแหน่ง i (เดินย้อนกลับข้าม vowel/tone marks จนเจอตัวที่ไม่ใช่ mark)
  function baseConsonantBefore(idx){
    for(let j = idx - 1; j >= 0; j--){
      const cj = str.charAt(j);
      if(SARA_TONE_ONLY.indexOf(cj) < 0 && SARA_ABOVE_VOWEL.indexOf(cj) < 0 && cj !== SARA_AM){
        return cj;
      }
    }
    return '';
  }

  // เช็คก่อนว่ามีกรณีต้องเลื่อนจริงไหม (กรณี 1-3 ข้างบน) — ถ้าไม่มีเลย วาด string เดียวจบ
  let needsShift = false;
  for(let i = 0; i < str.length && !needsShift; i++){
    const c = str.charAt(i);
    const prev = i > 0 ? str.charAt(i - 1) : '';
    if(SARA_ABOVE_VOWEL.indexOf(c) >= 0 && TALL_CONSONANTS.indexOf(baseConsonantBefore(i)) >= 0){
      needsShift = true; // กรณี 2
    } else if(SARA_TONE_ONLY.indexOf(c) >= 0){
      if(SARA_ABOVE_VOWEL.indexOf(prev) >= 0){
        if(TALL_CONSONANTS.indexOf(baseConsonantBefore(i)) >= 0) needsShift = true; // กรณี 3
      } else if(str.charAt(i + 1) !== SARA_AM){
        needsShift = true; // กรณี 1 (ไม่ตามด้วย ำ — ถ้าตามด้วย ำ ระยะเดิมถูกอยู่แล้ว ไม่ต้องเลื่อน)
      }
    }
  }
  if(!needsShift){
    doc.text(str, startX, y);
    return;
  }

  // มีกรณีต้องเลื่อน — เดินวาดทีละตัวอักษร สะสมตำแหน่ง x ด้วย getTextWidth ของแต่ละตัว
  // (ทดสอบแล้วว่า getTextWidth ของฟอนต์นี้บวกกันได้ตรงกับความกว้างของ string เต็มเป๊ะ เพราะ
  // จุด/วรรณยุกต์ทุกตัวมี advance=0 ในฟอนต์นี้อยู่แล้ว — ไม่ใช่การกะระยะเองแบบรอบ 1-4)
  const shiftDownNormalMM = doc.getFontSize() * TONE_SHIFT_DOWN_NORMAL * 0.3527778;
  const shiftDownTallMM   = doc.getFontSize() * TONE_SHIFT_DOWN_TALL * 0.3527778;
  const shiftUpTallMM     = doc.getFontSize() * MARK_SHIFT_UP_TALL * 0.3527778;
  let cx = startX;
  for(let i = 0; i < str.length; i++){
    const c = str.charAt(i);
    const prev = i > 0 ? str.charAt(i - 1) : '';
    const isTall = TALL_CONSONANTS.indexOf(baseConsonantBefore(i)) >= 0;
    let drawY = y;

    if(SARA_ABOVE_VOWEL.indexOf(c) >= 0 && isTall){
      drawY = y - shiftUpTallMM; // กรณี 2: สระบนติด ป/ฝ/ฟ
    } else if(SARA_TONE_ONLY.indexOf(c) >= 0){
      if(SARA_ABOVE_VOWEL.indexOf(prev) >= 0){
        if(isTall) drawY = y - shiftUpTallMM; // กรณี 3: ตามหลังสระที่เพิ่งเลื่อนขึ้น
      } else if(str.charAt(i + 1) !== SARA_AM){
        drawY = y + (isTall ? shiftDownTallMM : shiftDownNormalMM); // กรณี 1
      }
    }

    doc.text(c, cx, drawY);
    cx += doc.getTextWidth(c);
  }
}

// สร้าง jsPDF doc พื้นฐาน A4 พร้อมฟอนต์ไทย + ครุฑกลางหน้าบน + หัวเรื่อง 'บันทึกข้อความ'
// docTitle: ข้อความหัวเรื่อง (ถ้าไม่ระบุ ใช้ 'บันทึกข้อความ')
function createDocBase(docTitle){
  const doc = new jspdf.jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
  registerThaiFont(doc);

  // ครุฑ: width=18mm height=22mm, x=(210-18)/2=96mm, y=10mm (ตาม BLUEPRINT §6.3)
  doc.addImage(GARUDA_B64, 'JPEG', 96, 10, 18, 22);

  doc.setFont('THSarabun', 'bold');
  doc.setFontSize(18);
  thaiText(doc, docTitle || 'บันทึกข้อความ', 105, 40, { align: 'center' });

  doc.setFont('THSarabun', 'normal');
  doc.setFontSize(16);

  return doc;
}
